  ('real-estate-moex-01084', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '夫妻之財產及所得，除特有財產外，合併為共同財產者，屬於下述何種所有型態？', '["夫妻公同共有", "夫妻分別共有", "夫妻區分所有", "夫妻總體共有"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01085', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡，由配偶乙繼承其遺產，乙對於甲所積欠丙之債務，應負何種責任？', '["負無限清償責任", "負部分清償責任", "不負責任", "以因繼承所得遺產為限負清償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01086', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '因他人拋棄繼承而應為繼承之人，為拋棄繼承時，應於知悉其得繼承之日起多久為之？', '["一個月", "二個月", "三個月", "六個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01087', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙約定為共同財產制為其夫妻財產制，其後甲死亡，繼承人為乙及生女丙，經查甲、乙之共同財產 共價值新臺幣100萬元，乙得分得金額為：', '["新臺幣75萬元", "新臺幣50萬元", "新臺幣100萬元", "新臺幣25萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01088', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男乙女婚姻關係存續中生女丙。嗣後甲乙離婚，甲男另與戊結婚，並由戊收養未成年之丙。丙成年後 與丁男結婚但尚無子女，某日丙女因故死亡。問丙之遺產應如何繼承？', '["由甲、乙、丁共同繼承，每人之應繼分為三分之一", "由甲、乙、丁共同繼承，惟丁之應繼分為二分之一", "由甲、戊、丁共同繼承，每人之應繼分為三分之一", "由甲、戊、丁共同繼承，惟丁之應繼分為二分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01089', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '繼承人在繼承開始前幾年內，從被繼承人受有財產之贈與者，該財產視為其所得遺產？', '["半年內", "1年內", "2年內", "3年內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01090', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '繼承開始時，繼承人之有無不明者，由親屬會議於一個月內選定遺產管理人，並將繼承開始及選定遺產 管理人之事由，向法院報明。關於遺產管理人之職務，以下敘述何者正確？', '["編製遺產清冊，並為保存遺產必要之處置。遺產清冊，管理人應於就職後六個月內編製之", "聲請法院依公示催告程序，限定六個月以上之期間，公告被繼承人之債權人及受遺贈人，命其於該期 間內報明債權及為願受遺贈與否之聲明，被繼承人之債權人及受遺贈人為管理人所已知者，應分別通 知之", "清償債權或交付遺贈物。惟遺贈物之交付，應先於債權之清償", "有繼承人承認繼承或遺產歸屬國庫時，為遺產之移交"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01091', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有配偶乙及子丙，甲生前預立遺囑，內容表示死後要將全部財產遺贈給好友丁，嗣甲死亡時，全部遺 產為新臺幣（下同）100萬元，試問受遺贈人丁可得多少？', '["100萬元", "75萬元", "50萬元", "20萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01092', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙建設公司購買預售屋一戶，約定甲應依已完成之工程進度所定付款明細表之規定於工程完工 後繳款，半年後乙建設公司資金週轉不靈，財產遭法院查封，甲是否應繼續繳納約定的工程款？', '["資金週轉不靈，屬可歸責於乙建設公司之事由，甲可拒絕繳納已完工的工程款", "因甲無過失，可免給付之義務，甲可拒絕繳納已完工的工程款", "基於買賣契約，甲得向乙建設公司主張同時履行抗辯，拒絕繳納已完工的工程款", "甲可主張在乙建設公司未繼續進行工程或提出擔保前，得拒絕繳納已完工的工程款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01093', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有A屋委託乙仲介公司銷售，定價新臺幣980萬元，丙經乙仲介公司銷售人員帶看之後， 對A屋甚是滿意，但是希望價格能降為新臺幣950萬元，乃給付新臺幣20萬元斡旋金予乙仲介公司 作為與屋主斡旋差價之用。下列敘述何者正確？', '["丙交付新臺幣20萬元斡旋金，為定金之給付，推定該買賣契約成立", "丙交付新臺幣20萬元斡旋金，為要約之引誘，買賣契約尚未成立", "丙交付新臺幣20萬元斡旋金，為新要約，買賣契約尚未成立", "丙交付新臺幣20萬元斡旋金，為要約之承諾，買賣契約成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
